<template><view class="page"><xy-header title="开通会员"/><view class="wrap"><view v-for="plan in plans" :key="plan.planId" class="card" :class="{on:selected&&selected.planId===plan.planId}" @click="selected=plan"><text class="name">{{plan.planName}}</text><text>有效期 {{plan.durationDays}} 天 · 每日可预约 {{plan.dailyReservationLimit}} 次</text><text class="price">¥{{plan.amount}}</text></view><view v-if="!plans.length" class="empty">暂无可购买套餐</view><button class="pay" :disabled="!selected||paying" @click="pay">{{paying?'支付准备中…':'微信支付开通'}}</button></view></view></template>
<script>import{appRequest,ensureMemberSession,publicRequest,showRequestError}from'../../utils/api';export default{data(){return{plans:[],selected:null,paying:false}},onLoad(){this.load()},methods:{async load(){try{this.plans=await publicRequest({url:'/app/membership-plans'});this.selected=this.plans[0]||null}catch(e){showRequestError(e)}},async pay(){this.paying=true;try{await ensureMemberSession();const p=await appRequest({url:`/app/membership-payments/${this.selected.planId}`,method:'POST'});uni.requestPayment({...p,success:()=>uni.redirectTo({url:'/pages/membership/card'}),fail:()=>uni.showToast({title:'支付未完成',icon:'none'})})}catch(e){showRequestError(e)}finally{this.paying=false}}}}</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{margin-bottom:18rpx;padding:28rpx;border:3rpx solid transparent;border-radius:22rpx;background:#fff}.card.on{border-color:var(--xy-primary)}.name,.price{display:block;font-weight:700}.name{font-size:32rpx}.card>text:nth-child(2){display:block;margin:14rpx 0;color:var(--xy-ink-3)}.price{color:var(--xy-danger);font-size:38rpx}.pay{margin-top:30rpx;background:var(--xy-primary);color:#fff}.empty{padding:120rpx;text-align:center;color:var(--xy-muted)}</style>
